import React from 'react';
import { ListBox as CarbonListBox } from '@carbon/react';

const ListBox = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonListBox
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonListBox>
    );
};

ListBox.defaultProps = {
    className: ''
};

export default ListBox;
